use loom::sync::{Arc, atomic::{AtomicUsize, Ordering}};
use loom::thread;

#[test]
fn loom_cancel_ready_interleaving() {
    loom::model(|| {
        let cancel_queue = Arc::new(Queue::new());
        let ready_queue = Arc::new(Queue::new());
        let consecutive_cancel = Arc::new(AtomicUsize::new(0));
        const MAX: usize = 2; // Small for Loom

        // Injector threads
        let cq = Arc::clone(&cancel_queue);
        thread::spawn(move || { cq.push(1); cq.push(2); cq.push(3); });

        let rq = Arc::clone(&ready_queue);
        thread::spawn(move || { rq.push(10); });

        // Worker thread with fairness
        let cq = Arc::clone(&cancel_queue);
        let rq = Arc::clone(&ready_queue);
        let cc = Arc::clone(&consecutive_cancel);
        let worker = thread::spawn(move || {
            let mut executed = vec![];
            loop {
                if cc.load(Ordering::Relaxed) < MAX {
                    if let Some(task) = cq.pop() {
                        cc.fetch_add(1, Ordering::Relaxed);
                        executed.push(('c', task));
                        continue;
                    }
                }
                if let Some(task) = rq.pop() {
                    cc.store(0, Ordering::Relaxed);
                    executed.push(('r', task));
                    continue;
                }
                if cq.is_empty() && rq.is_empty() {
                    break;
                }
            }
            executed
        });

        let executed = worker.join().unwrap();

        // Ready task should not be last if cancels are available
        // (fairness should let it run)
        if executed.len() > 3 {
            // At some point, ready should have run between cancels
            let ready_idx = executed.iter().position(|&(t, _)| t == 'r');
            assert!(ready_idx.is_some(), "ready work never executed");
        }
    });
}
```

